variables.scriptContent:
param(
    [string]$SmtpServer,
    [int]$SmtpPort = 587,
    [string]$FromAddresses,
    [string]$ToAddresses,
    [string]$SubjectLines,
    [string]$AttachmentUrls,
    [string]$PhishingTestUrls,
    [int]$EmailsPerRecipient = 20,
    [int]$ThreatTestPercentage = 30
)

$ErrorActionPreference = 'Stop'

Write-Output "$(Get-Date) === Send-Emails SMTP Script ==="
Write-Output "$(Get-Date) SMTP Server: $SmtpServer : $SmtpPort"
Write-Output "$(Get-Date) From: $FromAddresses"
Write-Output "$(Get-Date) Emails per recipient: $EmailsPerRecipient"
Write-Output "$(Get-Date) Threat percentage: $ThreatTestPercentage%"

# --- Parse phishing URLs ---
$phishUrls = @()
if ($PhishingTestUrls) {
    $phishUrls = @($PhishingTestUrls -split '\|' | ForEach-Object { $_.Trim() } | Where-Object { $_ })
}
Write-Output "$(Get-Date) Phishing test URLs loaded: $($phishUrls.Count)"

# --- Parse custom subject lines ---
$customSubjects = @()
if ($SubjectLines) {
    $customSubjects = @($SubjectLines -split '\|' | ForEach-Object { $_.Trim() } | Where-Object { $_ })
}
Write-Output "$(Get-Date) Custom subjects loaded: $($customSubjects.Count)"

# --- Fallback text for random subject/body generation ---
$fallbackWords = @('Urgent','Meeting','Update','Invoice','Review','Quarterly','Report','Action','Required','Approval','Budget','Forecast','Schedule','Compliance','Security','Training','Deadline','Reminder','Contract','Proposal','Summary','Feedback','Notification','Alert','Request','Confirmation','Delivery','Shipment','Account','Verification','Password','Reset','Subscription','Renewal','Payment','Receipt','Refund','Dispute','Warranty','Support','Ticket','Incident','Resolution','Escalation','Priority','Critical','Advisory','Bulletin','Release','Patch','Maintenance','Outage','Restore','Backup','Audit','Policy','Procedure','Guidelines','Standards','Framework','Assessment','Evaluation','Performance','Metrics','Dashboard','Analytics','Insights','Trends','Benchmark','Optimization','Strategy','Roadmap','Initiative','Project','Milestone','Deliverable','Stakeholder','Collaboration','Integration','Migration','Deployment','Configuration','Documentation','Specification','Architecture','Infrastructure','Capacity','Scalability','Availability','Reliability','Monitoring','Alerting','Logging','Diagnostics','Troubleshooting','Resolution','Workaround','Hotfix','Rollback','Recovery','Contingency','Continuity')

# --- Download custom attachments ---
$attachmentFiles = @()
if ($AttachmentUrls) {
    $urls = @($AttachmentUrls -split '\|' | ForEach-Object { $_.Trim() } | Where-Object { $_ })
    $dlDir = Join-Path $env:HOME 'attachments'
    New-Item -Path $dlDir -ItemType Directory -Force | Out-Null
    foreach ($url in $urls) {
        try {
            $fileName = [System.IO.Path]::GetFileName(([uri]$url).LocalPath)
            if (-not $fileName) { $fileName = 'attachment.bin' }
            $destPath = Join-Path $dlDir $fileName
            Write-Output "$(Get-Date) Downloading attachment: $url"
            Invoke-WebRequest -Uri $url -OutFile $destPath -UseBasicParsing -TimeoutSec 60
            $attachmentFiles += $destPath
            Write-Output "$(Get-Date) Downloaded: $fileName ($((Get-Item $destPath).Length) bytes)"
        } catch {
            Write-Warning "Failed to download $url : $_"
        }
    }
}
Write-Output "$(Get-Date) Custom attachments available: $($attachmentFiles.Count)"

# --- Create EICAR test file ---
$eicarString = 'X5O!P%@AP[4\PZX54(P^)7CC)7}$EICAR-STANDARD-ANTIVIRUS-TEST-FILE!$H+H*'
$eicarPath = Join-Path $env:HOME 'eicar_test.txt'
Set-Content -Path $eicarPath -Value $eicarString -NoNewline
Write-Output "$(Get-Date) EICAR test file created."

# --- GTUBE string ---
$gtubeString = 'XJS*C4JDBQADN1.NSBN3*2IDNEN*GTUBE-STANDARD-ANTI-UBE-TEST-EMAIL*C.34X'

# --- Helper functions ---
function Get-RandomSubject {
    if ($customSubjects.Count -gt 0) {
        return $customSubjects[(Get-Random -Maximum $customSubjects.Count)]
    }
    $wordCount = Get-Random -Minimum 2 -Maximum 8
    $words = 1..$wordCount | ForEach-Object { $fallbackWords[(Get-Random -Maximum $fallbackWords.Count)] }
    return ($words -join ' ')
}

function Get-RandomBody {
    $wordCount = Get-Random -Minimum 50 -Maximum 300
    $words = 1..$wordCount | ForEach-Object { $fallbackWords[(Get-Random -Maximum $fallbackWords.Count)] }
    return ($words -join ' ')
}

function Send-SmtpEmail {
    param(
        [string]$From,
        [string]$To,
        [string]$Subject,
        [string]$Body,
        [string]$AttachmentPath,
        [string]$Server,
        [int]$Port
    )
    $msg = New-Object System.Net.Mail.MailMessage
    $msg.From = $From
    $msg.To.Add($To)
    $msg.Subject = $Subject
    $msg.Body = $Body
    $msg.IsBodyHtml = $false
    if ($AttachmentPath -and (Test-Path $AttachmentPath)) {
        $attach = New-Object System.Net.Mail.Attachment($AttachmentPath)
        $msg.Attachments.Add($attach)
    }
    $smtp = New-Object System.Net.Mail.SmtpClient($Server, $Port)
    if ($Port -eq 587) {
        $smtp.EnableSsl = $true
    }
    $smtp.Timeout = 30000
    try {
        $smtp.Send($msg)
    } finally {
        if ($msg.Attachments) { $msg.Attachments.Dispose() }
        $msg.Dispose()
        $smtp.Dispose()
    }
}

# --- Parse sender addresses ---
$senders = @($FromAddresses -split ',' | ForEach-Object { $_.Trim() } | Where-Object { $_ })
Write-Output "$(Get-Date) Senders loaded: $($senders.Count) - $($senders -join ', ')"

# --- Main send loop ---
$recipients = @($ToAddresses -split ',' | ForEach-Object { $_.Trim() } | Where-Object { $_ })
Write-Output "$(Get-Date) Recipients loaded: $($recipients.Count) - $($recipients -join ', ')"
Write-Output "$(Get-Date) Target: $EmailsPerRecipient emails x $($recipients.Count) recipients"
$threatThreshold = [math]::Floor($ThreatTestPercentage / 10)
$sentCount = 0
$round = 0

# Track per-recipient counts
$recipientCount = @{}
foreach ($r in $recipients) { $recipientCount[$r] = 0 }

while (($recipientCount.Values | Where-Object { $_ -lt $EmailsPerRecipient }).Count -gt 0) {
    $round++
    $sender = $senders[(Get-Random -Maximum $senders.Count)]
    $remaining = @($recipientCount.Keys | Where-Object { $recipientCount[$_] -lt $EmailsPerRecipient })
    $pickCount = [math]::Min(5, $remaining.Count)
    $selectedRecipients = $remaining | Get-Random -Count $pickCount

    $subject = Get-RandomSubject
    $body = Get-RandomBody
    $attachPath = $null
    $threatType = 'clean'

    if ($attachmentFiles.Count -gt 0 -and (Get-Random -Minimum 1 -Maximum 11) -le 3) {
        $attachPath = $attachmentFiles[(Get-Random -Maximum $attachmentFiles.Count)]
    }

    $injectThreat = (Get-Random -Minimum 1 -Maximum 11) -le $threatThreshold
    if ($injectThreat) {
        $threatChoice = Get-Random -Minimum 1 -Maximum 4
        switch ($threatChoice) {
            1 {
                $body += "`n`n$gtubeString`n"
                $threatType = 'GTUBE-SPAM'
            }
            2 {
                if ($phishUrls.Count -gt 0) {
                    $randomUrl = $phishUrls[(Get-Random -Maximum $phishUrls.Count)]
                    $body += "`nPlease verify your account immediately: $randomUrl`n"
                    $threatType = 'PHISH-URL'
                }
            }
            3 {
                $attachPath = $eicarPath
                $threatType = 'EICAR-MALWARE'
            }
        }
    }

    $attachName = if ($attachPath) { Split-Path $attachPath -Leaf } else { 'none' }
    foreach ($recipient in $selectedRecipients) {
        try {
            Send-SmtpEmail -From $sender -To $recipient -Subject $subject -Body $body -AttachmentPath $attachPath -Server $SmtpServer -Port $SmtpPort
            $recipientCount[$recipient]++
            Write-Output "[Round $round] -> $recipient ($($recipientCount[$recipient])/$EmailsPerRecipient) [$threatType] Subject: $subject Attach: $attachName"
            $sentCount++
        } catch {
            Write-Warning "[Round $round] -> $recipient FAILED: $_"
        }
    }
    Start-Sleep -Milliseconds 500
}

Write-Output "`n$(Get-Date) Complete. Sent $sentCount total messages ($EmailsPerRecipient each to $($recipients.Count) recipients) in $round rounds."
